namespace Lumeo;

/// <summary>
/// Context for a clicked data cell in a <see cref="PivotGrid{TItem}"/>, useful for drill-down.
/// </summary>
public sealed class PivotCellClickArgs
{
    /// <summary>The row-hierarchy path (one value per row field) identifying the clicked row.</summary>
    public IReadOnlyList<object?> RowKeys { get; }

    /// <summary>The column-hierarchy path identifying the clicked column. Empty when there is no column field.</summary>
    public IReadOnlyList<object?> ColumnKeys { get; }

    /// <summary>Header of the measure that was clicked.</summary>
    public string Measure { get; }

    /// <summary>The underlying source rows that contributed to the clicked cell.</summary>
    public IReadOnlyList<object?> Items { get; }

    public PivotCellClickArgs(IReadOnlyList<object?> rowKeys, IReadOnlyList<object?> columnKeys,
        string measure, IReadOnlyList<object?> items)
    {
        RowKeys = rowKeys;
        ColumnKeys = columnKeys;
        Measure = measure;
        Items = items;
    }
}

namespace Lumeo;

/// <summary>
/// Describes a field used to build a row- or column-hierarchy level in a
/// <see cref="PivotGrid{TItem}"/>. The distinct values produced by
/// <see cref="Selector"/> form the groups at that level.
/// </summary>
/// <typeparam name="TItem">The flat source row type.</typeparam>
public sealed class PivotField<TItem>
{
    /// <summary>Header label shown for this field level.</summary>
    public string Header { get; init; } = "";

    /// <summary>Extracts the grouping value for this field from a source row.</summary>
    public Func<TItem, object?> Selector { get; init; } = _ => null;

    /// <summary>Optional formatter for the displayed group label. Receives the raw value.</summary>
    public Func<object?, string>? Format { get; init; }

    /// <summary>Optional custom ordering of the distinct values. When null, values are sorted naturally.</summary>
    public IComparer<object?>? SortComparer { get; init; }

    public PivotField() { }

    public PivotField(string header, Func<TItem, object?> selector,
        Func<object?, string>? format = null, IComparer<object?>? sortComparer = null)
    {
        Header = header;
        Selector = selector;
        Format = format;
        SortComparer = sortComparer;
    }

    internal string FormatValue(object? value)
        => Format is not null ? Format(value) : (value?.ToString() ?? "—");
}

@namespace Lumeo
@typeparam TItem

<div class="@WrapperClass" @attributes="AdditionalAttributes">
    @if (_isEmpty)
    {
        <div class="p-6 text-sm text-muted-foreground text-center">
            @if (EmptyContent is not null)
            {
                @EmptyContent
            }
            else
            {
                <span>No data to display.</span>
            }
        </div>
    }
    else
    {
        <div class="relative w-full overflow-auto">
            <table role="table" class="w-full caption-bottom text-sm border-collapse">
                <thead>
                    <tr role="row" class="border-b border-border/40">
                        @foreach (var rf in _rowFields)
                        {
                            <th role="columnheader" rowspan="@HeaderRowSpan"
                                class="@HeaderCellClass align-bottom text-left">@rf.Header</th>
                        }
                        @if (_hasColumnField)
                        {
                            @foreach (var col in _columnLeaves)
                            {
                                <th role="columnheader" colspan="@_measures.Count" class="@HeaderCellClass text-center">@col.Label</th>
                            }
                            @if (ShowRowGrandTotal)
                            {
                                <th role="columnheader" colspan="@_measures.Count" class="@HeaderCellClass text-center bg-muted/50">@GrandTotalLabel</th>
                            }
                        }
                        else
                        {
                            @foreach (var m in _measures)
                            {
                                <th role="columnheader" class="@HeaderCellClass text-right">@m.Header</th>
                            }
                        }
                    </tr>
                    @if (_hasColumnField)
                    {
                        <tr role="row" class="border-b border-border/40">
                            @foreach (var col in _columnLeaves)
                            {
                                @foreach (var m in _measures)
                                {
                                    <th role="columnheader" class="@HeaderCellClass text-right">@m.Header</th>
                                }
                            }
                            @if (ShowRowGrandTotal)
                            {
                                @foreach (var m in _measures)
                                {
                                    <th role="columnheader" class="@HeaderCellClass text-right bg-muted/50">@m.Header</th>
                                }
                            }
                        </tr>
                    }
                </thead>
                <tbody>
                    @foreach (var row in _displayRows)
                    {
                        <tr role="row" class="@RowClass(row)">
                            @* --- row-header columns --- *@
                            @if (row.Kind == DisplayRowKind.Leaf)
                            {
                                @for (var i = 0; i < _rowFields.Count; i++)
                                {
                                    <td role="rowheader" class="@DataCellClass">@(i == row.Level ? row.Label : "")</td>
                                }
                            }
                            else
                            {
                                @for (var i = 0; i < row.Level; i++)
                                {
                                    <td role="rowheader" class="@DataCellClass"></td>
                                }
                                <td role="rowheader" colspan="@(_rowFields.Count - row.Level)"
                                    class="@DataCellClass font-medium">
                                    @if (row.Kind == DisplayRowKind.GroupHeader && Collapsible)
                                    {
                                        <button type="button" aria-expanded="@((!row.Collapsed).ToString().ToLowerInvariant())"
                                                class="inline-flex items-center gap-1 hover:text-primary transition-colors"
                                                @onclick="() => ToggleCollapse(row.Node)">
                                            <Blazicon Svg="@(row.Collapsed ? Lucide.ChevronRight : Lucide.ChevronDown)" class="w-3.5 h-3.5 shrink-0" />
                                            <span>@row.Label</span>
                                        </button>
                                    }
                                    else if (row.Kind == DisplayRowKind.Subtotal)
                                    {
                                        <span>@row.Label Total</span>
                                    }
                                    else
                                    {
                                        <span>@row.Label</span>
                                    }
                                </td>
                            }
                            @* --- data columns --- *@
                            @if (_hasColumnField)
                            {
                                @foreach (var col in _columnLeaves)
                                {
                                    @for (var mi = 0; mi < _measures.Count; mi++)
                                    {
                                        var measure = _measures[mi];
                                        var matched = MatchCell(row.Node, col);
                                        var mIndex = mi;
                                        var theCol = col;
                                        <td role="cell" class="@DataCellClass tabular-nums text-right"
                                            @onclick="() => OnCellClickHandler(row, theCol, mIndex)">@measure.FormatValue(measure.Compute(matched))</td>
                                    }
                                }
                                @if (ShowRowGrandTotal)
                                {
                                    @foreach (var m in _measures)
                                    {
                                        <td role="cell" class="@DataCellClass tabular-nums text-right bg-muted/30 font-medium">@m.FormatValue(m.Compute(row.Node.Items))</td>
                                    }
                                }
                            }
                            else
                            {
                                @for (var mi = 0; mi < _measures.Count; mi++)
                                {
                                    var measure = _measures[mi];
                                    var mIndex = mi;
                                    <td role="cell" class="@DataCellClass tabular-nums text-right"
                                        @onclick="() => OnCellClickHandler(row, null, mIndex)">@measure.FormatValue(measure.Compute(row.Node.Items))</td>
                                }
                            }
                        </tr>
                    }
                    @if (ShowColumnGrandTotal)
                    {
                        <tr role="row" class="bg-muted/50 font-semibold border-t border-border/40">
                            <td role="rowheader" colspan="@_rowFields.Count" class="@DataCellClass">@GrandTotalLabel</td>
                            @if (_hasColumnField)
                            {
                                @foreach (var col in _columnLeaves)
                                {
                                    @foreach (var m in _measures)
                                    {
                                        <td role="cell" class="@DataCellClass tabular-nums text-right">@m.FormatValue(m.Compute(col.Items))</td>
                                    }
                                }
                                @if (ShowRowGrandTotal)
                                {
                                    @foreach (var m in _measures)
                                    {
                                        <td role="cell" class="@DataCellClass tabular-nums text-right bg-muted/50">@m.FormatValue(m.Compute(_allItems))</td>
                                    }
                                }
                            }
                            else
                            {
                                @foreach (var m in _measures)
                                {
                                    <td role="cell" class="@DataCellClass tabular-nums text-right">@m.FormatValue(m.Compute(_allItems))</td>
                                }
                            }
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    // ---- Parameters ----------------------------------------------------

    [Parameter] public IEnumerable<TItem>? Items { get; set; }
    [Parameter] public IReadOnlyList<PivotField<TItem>> RowFields { get; set; } = Array.Empty<PivotField<TItem>>();
    [Parameter] public IReadOnlyList<PivotField<TItem>> ColumnFields { get; set; } = Array.Empty<PivotField<TItem>>();
    [Parameter] public IReadOnlyList<PivotMeasure<TItem>> Measures { get; set; } = Array.Empty<PivotMeasure<TItem>>();

    [Parameter] public bool ShowRowGrandTotal { get; set; } = true;
    [Parameter] public bool ShowColumnGrandTotal { get; set; } = true;
    [Parameter] public bool ShowSubtotals { get; set; } = true;
    [Parameter] public bool Collapsible { get; set; } = true;
    [Parameter] public bool Compact { get; set; }
    [Parameter] public string GrandTotalLabel { get; set; } = "Grand Total";

    [Parameter] public RenderFragment? EmptyContent { get; set; }

    /// <summary>Invoked when a data cell is clicked. Carries the clicked cell context for drill-down.</summary>
    [Parameter] public EventCallback<PivotCellClickArgs> OnCellClick { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // ---- Cached state (computed in OnParametersSet) --------------------

    private List<TItem> _allItems = new();
    private IReadOnlyList<PivotField<TItem>> _rowFields = Array.Empty<PivotField<TItem>>();
    private IReadOnlyList<PivotMeasure<TItem>> _measures = Array.Empty<PivotMeasure<TItem>>();
    private PivotField<TItem>? _colField;
    private bool _hasColumnField;
    private bool _isEmpty;

    private List<ColumnLeaf> _columnLeaves = new();
    private RowNode _root = new(Array.Empty<object?>(), -1);
    private List<DisplayRow> _displayRows = new();

    private readonly HashSet<string> _collapsed = new();

    private string WrapperClass => $"rounded-lg border border-border/40 bg-card text-foreground overflow-hidden {Class}".Trim();
    private string HeaderCellClass => (Compact ? "px-2 py-1.5" : "px-3 py-2") + " text-xs font-medium text-foreground bg-muted/40 border border-border/40 whitespace-nowrap";
    private string DataCellClass => (Compact ? "px-2 py-1.5" : "px-3 py-2") + " border border-border/40 whitespace-nowrap";
    private int HeaderRowSpan => _hasColumnField ? 2 : 1;

    protected override void OnParametersSet()
    {
        _allItems = (Items ?? Enumerable.Empty<TItem>()).ToList();
        _rowFields = RowFields ?? Array.Empty<PivotField<TItem>>();
        _measures = Measures ?? Array.Empty<PivotMeasure<TItem>>();
        // Only the first column field is honoured — single column-field level (see component docs).
        _colField = (ColumnFields is { Count: > 0 }) ? ColumnFields[0] : null;
        _hasColumnField = _colField is not null;
        _isEmpty = _allItems.Count == 0;

        if (_isEmpty)
        {
            _columnLeaves = new();
            _displayRows = new();
            return;
        }

        // --- column leaves (single level) ---
        _columnLeaves = new();
        if (_colField is not null)
        {
            var grouped = _allItems
                .GroupBy(i => _colField.Selector(i))
                .Select(g => (Key: g.Key, Items: (IReadOnlyList<TItem>)g.ToList()))
                .ToList();
            grouped.Sort((a, b) => CompareValues(a.Key, b.Key));
            if (_colField.SortComparer is { } sc)
                grouped = grouped.OrderBy(x => x.Key, sc).ToList();
            foreach (var g in grouped)
                _columnLeaves.Add(new ColumnLeaf(_colField.FormatValue(g.Key), g.Key, g.Items));
        }

        // --- row hierarchy tree ---
        _root = BuildNode(_allItems, Array.Empty<object?>(), -1);

        // --- flatten into display rows respecting collapse ---
        _displayRows = new();
        FlattenRows(_root);
    }

    private RowNode BuildNode(IReadOnlyList<TItem> items, object?[] path, int level)
    {
        // labels[i] = the formatted display label of path[i]
        var labels = new string[path.Length];
        for (var i = 0; i < path.Length; i++)
            labels[i] = _rowFields[i].FormatValue(path[i]);
        var node = new RowNode(path, level) { Items = items, Labels = labels };

        var childLevel = level + 1;
        if (childLevel < _rowFields.Count)
        {
            var field = _rowFields[childLevel];
            var groups = items
                .GroupBy(i => field.Selector(i))
                .Select(g => (Key: g.Key, Items: (IReadOnlyList<TItem>)g.ToList()))
                .ToList();
            groups.Sort((a, b) => CompareValues(a.Key, b.Key));
            if (field.SortComparer is { } sc)
                groups = groups.OrderBy(x => x.Key, sc).ToList();
            foreach (var g in groups)
            {
                var childPath = path.Append(g.Key).ToArray();
                node.Children.Add(BuildNode(g.Items, childPath, childLevel));
            }
        }
        return node;
    }

    private void FlattenRows(RowNode node)
    {
        foreach (var child in node.Children)
        {
            if (child.Children.Count == 0)
            {
                _displayRows.Add(new DisplayRow(child, DisplayRowKind.Leaf, false, child.Level, LeafLabel(child)));
            }
            else
            {
                var collapsed = _collapsed.Contains(child.Key);
                _displayRows.Add(new DisplayRow(child, DisplayRowKind.GroupHeader, collapsed, child.Level, LeafLabel(child)));
                if (!collapsed)
                    FlattenRows(child);
                if (ShowSubtotals)
                    _displayRows.Add(new DisplayRow(child, DisplayRowKind.Subtotal, false, child.Level, LeafLabel(child)));
            }
        }
    }

    private static string LeafLabel(RowNode n) => n.Labels.Length == 0 ? "" : n.Labels[^1];

    private IReadOnlyList<TItem> MatchCell(RowNode rowNode, ColumnLeaf col)
    {
        if (rowNode.Items.Count == 0 || _colField is null) return Array.Empty<TItem>();
        var list = new List<TItem>();
        foreach (var item in rowNode.Items)
            if (Equals(_colField.Selector(item), col.Key))
                list.Add(item);
        return list;
    }

    private void ToggleCollapse(RowNode node)
    {
        if (!Collapsible || node.Children.Count == 0) return;
        if (!_collapsed.Add(node.Key)) _collapsed.Remove(node.Key);
        _displayRows = new();
        FlattenRows(_root);
        StateHasChanged();
    }

    private async Task OnCellClickHandler(DisplayRow row, ColumnLeaf? col, int measureIndex)
    {
        if (!OnCellClick.HasDelegate) return;
        var matched = col is not null ? MatchCell(row.Node, col) : row.Node.Items;
        var args = new PivotCellClickArgs(
            row.Node.Path.ToArray(),
            col is not null ? new[] { col.Key } : Array.Empty<object?>(),
            (measureIndex >= 0 && measureIndex < _measures.Count) ? _measures[measureIndex].Header : "",
            matched.Cast<object?>().ToArray());
        await OnCellClick.InvokeAsync(args);
    }

    private static int CompareValues(object? a, object? b)
    {
        if (a is null && b is null) return 0;
        if (a is null) return -1;
        if (b is null) return 1;
        if (a is IComparable ca && a.GetType() == b.GetType()) return ca.CompareTo(b);
        return string.Compare(a.ToString(), b.ToString(), StringComparison.OrdinalIgnoreCase);
    }

    private string RowClass(DisplayRow row) => row.Kind switch
    {
        DisplayRowKind.Subtotal => "bg-muted/30 font-medium border-b border-border/40",
        DisplayRowKind.GroupHeader => "bg-muted/20 font-medium border-b border-border/40",
        _ => "border-b border-border/40 hover:bg-muted/30 transition-colors"
    };

    // ---- Internal model -----------------------------------------------

    private sealed class RowNode
    {
        public object?[] Path { get; }
        public int Level { get; }
        public IReadOnlyList<TItem> Items { get; set; } = Array.Empty<TItem>();
        public string[] Labels { get; set; } = Array.Empty<string>();
        public List<RowNode> Children { get; } = new();
        public string Key { get; }

        public RowNode(object?[] path, int level)
        {
            Path = path;
            Level = level;
            Key = "L" + level + "|" + string.Join("", path.Select(p => p?.ToString() ?? "�"));
        }
    }

    private sealed record ColumnLeaf(string Label, object? Key, IReadOnlyList<TItem> Items);

    private enum DisplayRowKind { GroupHeader, Leaf, Subtotal }

    private sealed record DisplayRow(RowNode Node, DisplayRowKind Kind, bool Collapsed, int Level, string Label);
}

namespace Lumeo;

/// <summary>How a <see cref="PivotMeasure{TItem}"/> aggregates the matching source rows.</summary>
public enum PivotAggregate
{
    Sum,
    Average,
    Count,
    Min,
    Max
}

/// <summary>
/// A value field for a <see cref="PivotGrid{TItem}"/> together with the
/// aggregation applied across the source rows in each cell.
/// </summary>
/// <typeparam name="TItem">The flat source row type.</typeparam>
public sealed class PivotMeasure<TItem>
{
    /// <summary>Header label for this measure.</summary>
    public string Header { get; init; } = "";

    /// <summary>Extracts the numeric value to aggregate from a source row.</summary>
    public Func<TItem, decimal> Value { get; init; } = _ => 0m;

    /// <summary>The aggregation function. Default is <see cref="PivotAggregate.Sum"/>.</summary>
    public PivotAggregate Aggregate { get; init; } = PivotAggregate.Sum;

    /// <summary>Optional formatter for the aggregated number. When null, a sensible default is used.</summary>
    public Func<decimal, string>? Format { get; init; }

    public PivotMeasure() { }

    public PivotMeasure(string header, Func<TItem, decimal> value,
        PivotAggregate aggregate = PivotAggregate.Sum, Func<decimal, string>? format = null)
    {
        Header = header;
        Value = value;
        Aggregate = aggregate;
        Format = format;
    }

    internal decimal Compute(IReadOnlyList<TItem> items)
    {
        if (Aggregate == PivotAggregate.Count)
            return items.Count;
        if (items.Count == 0)
            return 0m;
        return Aggregate switch
        {
            PivotAggregate.Sum => items.Sum(Value),
            PivotAggregate.Average => items.Average(Value),
            PivotAggregate.Min => items.Min(Value),
            PivotAggregate.Max => items.Max(Value),
            _ => items.Sum(Value)
        };
    }

    internal string FormatValue(decimal value)
    {
        if (Format is not null) return Format(value);
        // Counts are whole; everything else gets two decimals only when it isn't integral.
        if (Aggregate == PivotAggregate.Count) return value.ToString("N0");
        return value == decimal.Truncate(value) ? value.ToString("N0") : value.ToString("N2");
    }
}
